arrayPipelines.data:
[
  { 
    "$match": {{ ai_teammate_rfp_betajs.getMatchQuery() }} 
  },
  {
    "$project": {
      "created_at": 1,
      "client_id": 1,
      "user_id": 1,
      "event_id": 1,
      "conversation_id": 1,
      "platform": 1,
      "conversation_counter": 1,
      "status": 1,
      "total_time_seconds": 1,
      "preference": 1,
      "mode": 1,
      "executed_intents": 1,
      "source": 1,
      "tx_consumed": 1,
      // Path Aliasing
      "originalUserInput": "$request.originalUserInput",
      "responseText": "$response.response.text",
      "sourceNames": "$response.response.sources.name",
      "webSourceNames": "$response.response.webSources.name",
      "webSourceUrls": "$response.response.webSources.url",

      // The "Sanitizer" for Regex, Arrays, and Nulls
      "source_analysis_prompt": {
        "$cond": {
          "if": { "$isArray": "$source_analysis_prompt" },
          "then": { 
            "$reduce": {
              "input": "$source_analysis_prompt",
              "initialValue": "",
              "in": { "$concat": ["$$value", { "$cond": [{ "$eq": ["$$value", ""] }, "", " "] }, { "$toString": "$$this" }] }
            }
          },
          "else": { "$ifNull": [{ "$toString": "$source_analysis_prompt" }, ""] }
        }
      },
      "answerability_prompts": {
        "$cond": {
          "if": { "$isArray": "$answerability_prompts" },
          "then": { 
            "$reduce": {
              "input": "$answerability_prompts",
              "initialValue": "",
              "in": { "$concat": ["$$value", { "$cond": [{ "$eq": ["$$value", ""] }, "", " "] }, { "$toString": "$$this" }] }
            }
          },
          "else": { "$ifNull": [{ "$toString": "$answerability_prompts" }, ""] }
        }
      }
    }
  },
  { "$limit": 2000 }
]
